public AmountMST openingBalance()
{    
    return custTable.openBalanceMST(dateNull(), fromDate -1, toDate);
    //return fromDate ? (onlyOpen ? custTable.openBalanceMST(dateNull(), fromDate -1, toDate) : custTable.balanceMST(dateNull(), fromDate -1)) : 0.00;
}

