public void init()
{
    CompanyInfo companyInfo = CompanyInfo::find();

    companyCurrencyCode = Ledger::accountingCurrency(companyInfo.RecId);
    languageId = companyInfo.LanguageId;
}

public Query initCustTransQuery()
{
    Query query = new Query();//this.parmQuery();
    QueryBuildDataSource    qbds,custTransDataSource;

    qbds = query.addDataSource(tableNum(CustTable));
    qbds.addRange(fieldNum(CustTable,AccountNum)).value(queryValue(custAccount));
    custTransDataSource = qbds.addDataSource(tableNum(CustTrans));
    custTransDataSource.addRange(fieldNum(CustTrans,TransDate)).value(queryRange(fromDate, toDate));
    //custTransDataSource.addRange(fieldNum(CustTrans,AccountNum)).value(queryValue(custAccount));
    custTransDataSource.relations(true);
    custTransDataSource.joinMode(JoinMode::OuterJoin);
    //QueryBuildDataSource custTransDataSource = SysQuery::findOrCreateDataSource(query, tableNum(CustTrans), tableNum(CustTable));
    QueryBuildDataSource transactionReversalTransDataSource = custTransDataSource.addDataSource(tableNum(TransactionReversalTrans));
    QueryBuildDataSource bankLCcustTransDataSource;
    QueryBuildDataSource ds;



    transactionReversalTransDataSource.addLink(fieldNum(CustTrans, RecId), fieldNum(TransactionReversalTrans, RefRecId));
    transactionReversalTransDataSource.addLink(fieldNum(CustTrans, TableId), fieldNum(TransactionReversalTrans, RefTableId));
    transactionReversalTransDataSource.fetchMode(QueryFetchMode::One2One);
    transactionReversalTransDataSource.joinMode(JoinMode::OuterJoin);



    //if (fromDate || toDate)
    //{
    //    custTransDataSource.addRange(fieldNum(CustTrans,TransDate)).value(queryRange(fromDate, toDate));
    //}

    custTransDataSource.addSortField(fieldNum(CustTrans,TransDate));
    custTransDataSource.addSortField(fieldNum(CustTrans,Voucher));
    /*
    if (!includeReversed)
    {
        ds = vendTransDataSource.addDataSource(tableNum(TransactionReversalTrans));
        ds.joinMode(JoinMode::NoExistsJoin);
        ds.addLink(fieldNum(VendTrans,TableId), fieldNum(TransactionReversalTrans,RefTableId));
        ds.addLink(fieldNum(VendTrans,RecId), fieldNum(TransactionReversalTrans,RefRecId));
        ds.addRange(fieldNum(TransactionReversalTrans,Reversed)).value(enum2str(NoYes::Yes));
    }
    */
    return query;
}

public Query initvendTransQuery()
{
    Query                   query = new Query();//this.parmQuery();
    QueryBuildDataSource    qbds,vendTransDataSource;

    qbds = query.addDataSource(tableNum(VendTable));
    qbds.addRange(fieldNum(VendTable,AccountNum)).value(queryValue(vendAccount));
    vendTransDataSource = qbds.addDataSource(tableNum(VendTrans));
    vendTransDataSource.addRange(fieldNum(VendTrans,TransDate)).value(queryRange(fromDate, toDate));
    vendTransDataSource.relations(true);
    vendTransDataSource.joinMode(JoinMode::OuterJoin);
    QueryBuildDataSource transactionReversalTransDataSource = vendTransDataSource.addDataSource(tableNum(TransactionReversalTrans));
    QueryBuildDataSource bankLCcustTransDataSource;
    QueryBuildDataSource ds;

    transactionReversalTransDataSource.addLink(fieldNum(CustTrans, RecId), fieldNum(TransactionReversalTrans, RefRecId));
    transactionReversalTransDataSource.addLink(fieldNum(CustTrans, TableId), fieldNum(TransactionReversalTrans, RefTableId));
    transactionReversalTransDataSource.fetchMode(QueryFetchMode::One2One);
    transactionReversalTransDataSource.joinMode(JoinMode::OuterJoin);

    vendTransDataSource.addSortField(fieldNum(CustTrans,TransDate));
    vendTransDataSource.addSortField(fieldNum(CustTrans,Voucher));

    return query;
}

protected void populateVendAccountStatementIntTmpRil(boolean _isSchedule)
{
    #define.Detail("Detail")
    FinancialDimensionSetEntity     financialDimensionSetEntity;

    // <GBR>
    if (BrazilParameters::isEnabled())
    {
        // Get TmpTaxWithhold
        TmpTaxWithhold tmpTaxWithhold = TaxWithhold::calculateTmpTaxWithhold(vendTrans, vendTrans.TransDate);

        vendAccountStatementIntTmp.FiscalEstablishmentId = vendTrans.fiscalEstablishmentId_BR();
        vendAccountStatementIntTmp.TaxWithHoldAmount_BR = tmpTaxWithhold.TaxWithholdAmount;
    }
    // </GBR>

    if (tmpCustVendTransOpen.RecId !=0)
    {
        vendAccountStatementIntTmp.SumAmountMST = this.amountMST();
    }
    else
    {
        vendAccountStatementIntTmp.SumAmountMST = tmpCustVendTransOpen.AmountMST;
    }

    if (_isSchedule)
    {
        if (isConfigurationkeyEnabled(configurationKeyNum(PublicSector)))
        {
            VendTransOpen vendTransOpen = VendTransOpen::find(tmpCustVendTransOpen.TmpRecId);
            vendAccountStatementIntTmp.Txt = #Detail;                
        }
        else
        {
            vendAccountStatementIntTmp.Txt = #Detail;
        }

        vendAccountStatementIntTmp.IsDetail = enum2str(NoYes::Yes);
        vendAccountStatementIntTmp.SumAmountMST = 0.0;

        if (details == DiscCurrency::Currency)
        {
            vendAccountStatementIntTmp.AmountMST = tmpCustVendTransOpen.AmountMST;
        }
        else if (details == DiscCurrency::Disc)
        {
            vendAccountStatementIntTmp.AmountMST = 0.0;
        }
        vendAccountStatementIntTmp.TransDate = dateNull();
        vendAccountStatementIntTmp.Voucher = '';
        vendAccountStatementIntTmp.Invoice = '';
        vendAccountStatementIntTmp.AmountCur = tmpCustVendTransOpen.AmountMST;
        vendAccountStatementIntTmp.DueDate = tmpCustVendTransOpen.DueDate;
        vendAccountStatementIntTmp.PossibleCashDisc = 0.0;
        vendAccountStatementIntTmp.UtilizedCashDisc = 0.0;
        vendAccountStatementIntTmp.RemainAmountCur = 0.0;
        vendAccountStatementIntTmp.TmpDueDate = tmpCustVendTransOpen.DueDate;
        vendAccountStatementIntTmp.RemainAmountMST = tmpCustVendTransOpen.AmountMST;
        vendAccountStatementIntTmp.CurrencyCode = '';
    }
    else
    {
        vendAccountStatementIntTmp.CurrencyCode = vendTrans.CurrencyCode;
        vendAccountStatementIntTmp.Txt = vendTrans.Txt;
        vendAccountStatementIntTmp.TransDate = vendTrans.TransDate;
        vendAccountStatementIntTmp.Voucher = vendTrans.Voucher;
        /*
        if (offsetAccount)
        {
            vendAccountStatementIntTmp.OffsetAccount = custVendTransDetails.offsetAccount(custTrans.Voucher, custTrans.TransDate);
        }
        */
        vendAccountStatementIntTmp.Invoice = vendTrans.Invoice;
        vendAccountStatementIntTmp.AmountMST = vendTrans.AmountMST;//this.VendAmountMST();
        vendAccountStatementIntTmp.RemainAmountMST = vendTrans.remainAmountMST();
        vendAccountStatementIntTmp.AmountCur = vendTrans.AmountCur;
        vendAccountStatementIntTmp.RemainAmountCur = vendTrans.remainAmountCur();

        if (numberOfTransOpen > 1 || numberOfTransOpen == 0)
        {
            vendAccountStatementIntTmp.DueDate = dateNull();
            vendAccountStatementIntTmp.TmpDueDate = dateNull();
            vendAccountStatementIntTmp.TransOpen = 1;
        }
        else
        {
            vendAccountStatementIntTmp.DueDate = vendTrans.DueDate;

            if (vendAccountStatementIntTmp.RecId != 0)
            {
                vendAccountStatementIntTmp.TmpDueDate = tmpCustVendTransOpen.DueDate;
            }
            else
            {
                vendAccountStatementIntTmp.TmpDueDate = vendTrans.DueDate;
            }
            vendAccountStatementIntTmp.TransOpen = 2;
        }
        vendAccountStatementIntTmp.PossibleCashDisc = CurrencyExchangeHelper::curAmount2CurAmount(vendAccountStatementIntTmpProcessing.PossibleCashDisc, vendTrans.CurrencyCode, companyCurrencyCode);
    }

    vendAccountStatementIntTmp.UtilizedCashDisc = CurrencyExchangeHelper::curAmount2CurAmount(vendAccountStatementIntTmpProcessing.utilizedCashDisc, custTrans.CurrencyCode, companyCurrencyCode);

    vendAccountStatementIntTmp.TraceNum = transactionReversalTrans.TraceNum;
    vendAccountStatementIntTmp.Reversed = transactionReversalTrans.Reversed ? 'R' : '';
    vendAccountStatementIntTmp.LetterRemarks = FormLetterRemarks::find(CompanyInfo::languageId(), FormTextType::CustACStatement).Txt;

    GeneralJournalEntry generalJournalEntry;
    SubledgerVoucherGeneralJournalEntry subledgerVoucherGeneralJournalEntry;

    select firstonly RecId from generalJournalEntry
        exists join subledgerVoucherGeneralJournalEntry
            where subledgerVoucherGeneralJournalEntry.Voucher == vendTrans.Voucher
            && subledgerVoucherGeneralJournalEntry.AccountingDate == vendTrans.TransDate
            && subledgerVoucherGeneralJournalEntry.VoucherDataAreaId == vendTrans.DataAreaId
            && generalJournalEntry.RecId == subledgerVoucherGeneralJournalEntry.GeneralJournalEntry;

    if (generalJournalEntry)
    {
        vendAccountStatementIntTmp.GeneralJournalEntry = generalJournalEntry.RecId;
    }

    if (BankLCImportFeatureChecker::checkBankLCImportEnabled())
    {
        BankLCVendTrans bankLCVendTrans;

        select firstonly BankDocumentType, BankLCNumber
            from bankLCVendTrans
            where bankLCVendTrans.BankLCImportLine == vendTrans.BankLCImportLine;
        if (bankLCVendTrans && bankLCVendTrans.RecId != 0)
        {
            vendAccountStatementIntTmp.BankDocumentType = bankLCVendTrans.BankDocumentType;
        vendAccountStatementIntTmp.BankLCNumber = bankLCVendTrans.BankLCNumber;
        }

    }
    vendAccountStatementIntTmp.LedgerCurrencyCode   = Ledger::accountingCurrency(CompanyInfo::find().RecId);
    vendAccountStatementIntTmp.DefaultDimension = vendTrans.DefaultDimension;
    if (financialDimSet)
    {
        select firstonly financialDimensionSetEntity
            where financialDimensionSetEntity.Name == financialDimSet;

        if (financialDimensionSetEntity.SegmentName01)
        {
            vendAccountStatementIntTmp.SegmentValue01   = this.getFinDimValue(vendTrans.DefaultDimension, financialDimensionSetEntity.SegmentName01);
            vendAccountStatementIntTmp.SegmentName01    = financialDimensionSetEntity.SegmentName01;
        }
        if (financialDimensionSetEntity.SegmentName02)
        {
            vendAccountStatementIntTmp.SegmentValue02   = this.getFinDimValue(vendTrans.DefaultDimension, financialDimensionSetEntity.SegmentName02);
            vendAccountStatementIntTmp.SegmentName02    = financialDimensionSetEntity.SegmentName02;
        }
        if (financialDimensionSetEntity.SegmentName03)
        {
            vendAccountStatementIntTmp.SegmentValue03   = this.getFinDimValue(vendTrans.DefaultDimension, financialDimensionSetEntity.SegmentName03);
            vendAccountStatementIntTmp.SegmentName03    = financialDimensionSetEntity.SegmentName03;
        }
        if (financialDimensionSetEntity.SegmentName04)
        {
            vendAccountStatementIntTmp.SegmentValue04   = this.getFinDimValue(vendTrans.DefaultDimension, financialDimensionSetEntity.SegmentName04);
            vendAccountStatementIntTmp.SegmentName04    = financialDimensionSetEntity.SegmentName04;
        }
        if (financialDimensionSetEntity.SegmentName05)
        {
            vendAccountStatementIntTmp.SegmentValue05   = this.getFinDimValue(vendTrans.DefaultDimension, financialDimensionSetEntity.SegmentName05);
            vendAccountStatementIntTmp.SegmentName05    = financialDimensionSetEntity.SegmentName05;
        }
        if (financialDimensionSetEntity.SegmentName06)
        {
            vendAccountStatementIntTmp.SegmentValue06   = this.getFinDimValue(vendTrans.DefaultDimension, financialDimensionSetEntity.SegmentName06);
            vendAccountStatementIntTmp.SegmentName06    = financialDimensionSetEntity.SegmentName06;
        }
        if (financialDimensionSetEntity.SegmentName07)
        {
            vendAccountStatementIntTmp.SegmentValue07   = this.getFinDimValue(vendTrans.DefaultDimension, financialDimensionSetEntity.SegmentName07);
            vendAccountStatementIntTmp.SegmentName07    = financialDimensionSetEntity.SegmentName07;
        }
        if (financialDimensionSetEntity.SegmentName08)
        {
            vendAccountStatementIntTmp.SegmentValue08   = this.getFinDimValue(vendTrans.DefaultDimension, financialDimensionSetEntity.SegmentName08);
            vendAccountStatementIntTmp.SegmentName08    = financialDimensionSetEntity.SegmentName08;
        }
        if (financialDimensionSetEntity.SegmentName09)
        {
            vendAccountStatementIntTmp.SegmentValue09   = this.getFinDimValue(vendTrans.DefaultDimension, financialDimensionSetEntity.SegmentName09);
            vendAccountStatementIntTmp.SegmentName09    = financialDimensionSetEntity.SegmentName09;
        }
        if (financialDimensionSetEntity.SegmentName10)
        {
            vendAccountStatementIntTmp.SegmentValue10   = this.getFinDimValue(vendTrans.DefaultDimension, financialDimensionSetEntity.SegmentName10);
            vendAccountStatementIntTmp.SegmentName10    = financialDimensionSetEntity.SegmentName10;
        }
        if (financialDimensionSetEntity.SegmentName11)
        {
            vendAccountStatementIntTmp.SegmentValue11   = this.getFinDimValue(vendTrans.DefaultDimension, financialDimensionSetEntity.SegmentName11);
            vendAccountStatementIntTmp.SegmentName11    = financialDimensionSetEntity.SegmentName11;
        }
    }
}
